import { Schema, model, Document } from 'mongoose';

interface UserDocument extends Document {
  username: string;
  passwordHash: string;
  email: string;
  createdAt: Date;
}

const UserSchema = new Schema<UserDocument>({
  username: { type: String, required: true, unique: true },
  passwordHash: { type: String, required: true },
  email: { type: String, required: true, unique: true },
  createdAt: { type: Date, default: Date.now },
});

export default model<UserDocument>('User', UserSchema);

import UserModel from './user.model';
import { UserDTO } from './user.dto';

class UserRepository {
  async createUser(userDTO: UserDTO): Promise<UserDTO> {
    const user = new UserModel(userDTO);
    await user.save();
    return this.toUserDTO(user);
  }

  async findById(id: string): Promise<UserDTO | null> {
    const user = await UserModel.findById(id).exec();
    return user ? this.toUserDTO(user) : null;
  }

  async findByUsername(username: string): Promise<UserDTO | null> {
    const user = await UserModel.findOne({ username }).exec();
    return user ? this.toUserDTO(user) : null;
  }

  private toUserDTO(user: any): UserDTO {
    return {
      id: user._id,
      username: user.username,
      email: user.email,
      createdAt: user.createdAt,
    };
  }
}

export default new UserRepository();

import UserRepository from './user.repository';
import { UserDTO, CreateUserDTO } from './user.dto';

class UserService {
  async createUser(createUserDTO: CreateUserDTO): Promise<UserDTO> {
    return await UserRepository.createUser(createUserDTO);
  }

  async getUserById(id: string): Promise<UserDTO | null> {
    return await UserRepository.findById(id);
  }

  async getUserByUsername(username: string): Promise<UserDTO | null> {
    return await UserRepository.findByUsername(username);
  }
}

export default new UserService();

import { Request, Response, NextFunction } from 'express';
import UserService from './user.service';
import { CreateUserDTO, UserResponseDTO } from './user.dto';
import { userCreateValidator } from './user.validator';

class UserController {
  async registerUser(req: Request, res: Response, next: NextFunction) {
    try {
      const createUserDTO: CreateUserDTO = userCreateValidator(req.body);
      const user = await UserService.createUser(createUserDTO);
      res.status(201).json({ success: true, data: user, meta: { timestamp: new Date().toISOString() } });
    } catch (err) {
      next(err);
    }
  }
}

export default new UserController();

export interface UserDTO {
  id: string;
  username: string;
  email: string;
  createdAt: Date;
}

export interface CreateUserDTO {
  username: string;
  passwordHash: string;
  email: string;
}

export interface UserResponseDTO {
  success: boolean;
  data: UserDTO;
  meta: {
    timestamp: string;
  };
}

import { z } from 'zod';

const createUserSchema = z.object({
  username: z.string().min(3).max(20),
  passwordHash: z.string().min(8),
  email: z.string().email(),
});

export const userCreateValidator = (data: any) => {
  return createUserSchema.parse(data);
};
